"use client";

import { useMemo, useState } from "react";
import { AnimatePresence, motion } from "framer-motion";
import { DATASETS, getDataset } from "@/lib/datasets";
import { TEACHING_DATASETS } from "@/lib/lesson-data";
import {
  MODE_INFO,
  VIEW_MODES,
  buildHeatmapCells,
} from "@/lib/heatmap-utils";
import type { ViewMode } from "@/lib/types";
import { TermButton } from "@/components/glossary/TermButton";
import { Heatmap } from "./Heatmap";
import { Slider } from "./Slider";
import { LessonWizard } from "./lesson/LessonWizard";

type Tab = "learn" | "explore";

export function ClusteringDashboard() {
  const [tab, setTab] = useState<Tab>("learn");
  const [datasetId, setDatasetId] = useState("movies");
  const [mode, setMode] = useState<ViewMode>("original");
  const [contrast, setContrast] = useState(1.3);
  const [noise, setNoise] = useState(0.03);

  const dataset = getDataset(datasetId);
  const teaching = TEACHING_DATASETS.find((d) => d.id === datasetId)!;

  const cells = useMemo(
    () => buildHeatmapCells(dataset, mode, noise),
    [dataset, mode, noise],
  );

  const miniViews = VIEW_MODES.map((m) => ({
    mode: m,
    cells: buildHeatmapCells(dataset, m, noise),
    info: MODE_INFO[m],
  }));

  return (
    <div className="min-h-screen bg-[#FFFDF7] text-black">
      <div className="relative mx-auto max-w-4xl px-4 py-6 md:max-w-5xl md:px-6 md:py-8">
        <header className="mb-6 border-b-4 border-black pb-5">
          <p className="text-sm font-medium text-[#5c5c5c]">Visual Analytics · Exercise 5</p>
          <h1
            className="mt-1 text-3xl font-bold tracking-tight md:text-4xl"
            style={{ color: teaching.theme.accent }}
          >
            Cluster Lab
          </h1>
          <p className="readable mt-2 max-w-lg text-[15px]">
            Learn <TermButton termId="row-clustering">row</TermButton>,{" "}
            <TermButton termId="column-clustering">column</TermButton>, and{" "}
            <TermButton termId="biclustering">biclustering</TermButton> step by step.
          </p>

          <div className="mt-4 flex w-full">
            {(["learn", "explore"] as Tab[]).map((t) => (
              <button
                key={t}
                onClick={() => setTab(t)}
                className="flex-1 border-2 border-black py-3 text-sm font-bold md:flex-none md:px-6"
                style={{
                  backgroundColor: tab === t ? teaching.theme.accent : "#FFF",
                  color: tab === t ? "#FFF" : "#0A0A0A",
                  marginRight: t === "learn" ? -2 : 0,
                  zIndex: tab === t ? 2 : 1,
                }}
              >
                {t === "learn" ? "Learn" : "Explore"}
              </button>
            ))}
          </div>
        </header>

        <AnimatePresence mode="wait">
          {tab === "learn" ? (
            <motion.div
              key="learn"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
            >
              <LessonWizard datasetId={datasetId} onDatasetChange={setDatasetId} />
            </motion.div>
          ) : (
            <motion.div
              key="explore"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="space-y-4"
            >
              <p className="readable text-[15px]">
                Full <TermButton termId="heatmap">heatmap</TermButton> — use after completing the
                lesson.
              </p>

              <div className="flex flex-wrap gap-2">
                {DATASETS.map((d) => (
                  <button
                    key={d.id}
                    onClick={() => setDatasetId(d.id)}
                    className="border-2 border-black px-3 py-2 text-sm font-bold"
                    style={{
                      backgroundColor: datasetId === d.id ? d.theme.accent : "#FFF",
                      color: datasetId === d.id ? "#FFF" : "#0A0A0A",
                    }}
                  >
                    {d.title}
                  </button>
                ))}
              </div>

              <ExplorePanel
                dataset={dataset}
                mode={mode}
                onMode={setMode}
                contrast={contrast}
                onContrast={setContrast}
                noise={noise}
                onNoise={setNoise}
                cells={cells}
                miniViews={miniViews}
              />
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </div>
  );
}

function ExplorePanel({
  dataset,
  mode,
  onMode,
  contrast,
  onContrast,
  noise,
  onNoise,
  cells,
  miniViews,
}: {
  dataset: ReturnType<typeof getDataset>;
  mode: ViewMode;
  onMode: (m: ViewMode) => void;
  contrast: number;
  onContrast: (v: number) => void;
  noise: number;
  onNoise: (v: number) => void;
  cells: ReturnType<typeof buildHeatmapCells>;
  miniViews: {
    mode: ViewMode;
    cells: ReturnType<typeof buildHeatmapCells>;
    info: (typeof MODE_INFO)[ViewMode];
  }[];
}) {
  const info = MODE_INFO[mode];

  return (
    <>
      <div className="grid gap-4 md:grid-cols-[200px_1fr]">
        <aside className="space-y-3">
          <div className="border-2 border-black bg-white p-3">
            <p className="mb-2 text-xs font-semibold text-[#5c5c5c]">Mode</p>
            {VIEW_MODES.map((m) => (
              <button
                key={m}
                onClick={() => onMode(m)}
                className="mb-1 block w-full px-2 py-2 text-left text-sm font-bold"
                style={{
                  backgroundColor: mode === m ? dataset.theme.accent : "transparent",
                  color: mode === m ? "#FFF" : "#0A0A0A",
                }}
              >
                {MODE_INFO[m].title}
              </button>
            ))}
          </div>
          <div className="border-2 border-black bg-white p-3">
            <Slider
              label="Contrast"
              value={contrast}
              min={0.7}
              max={2.5}
              step={0.1}
              accent={dataset.theme.accent}
              onChange={onContrast}
              format={(v) => `${v.toFixed(1)}×`}
            />
            <div className="mt-4">
              <Slider
                label="Noise"
                value={noise}
                min={0}
                max={0.18}
                step={0.01}
                accent={dataset.theme.secondary}
                onChange={onNoise}
                format={(v) => `${(v * 100).toFixed(0)}%`}
              />
            </div>
          </div>
        </aside>

        <div className="border-2 border-black bg-white">
          <div
            className="border-b-2 border-black px-4 py-3"
            style={{ backgroundColor: dataset.theme.accentLight }}
          >
            <p className="font-bold">{dataset.title}</p>
            <p className="text-sm text-[#5c5c5c]">{info.subtitle}</p>
          </div>
          <div className="flex justify-center overflow-x-auto p-4">
            <Heatmap
              dataset={dataset}
              cells={cells}
              mode={mode}
              contrast={contrast}
              highlightBlock={dataset.biclusterBlock}
            />
          </div>
        </div>
      </div>

      <div className="grid grid-cols-2 gap-2 md:grid-cols-4">
        {miniViews.map(({ mode: m, cells: c, info: i }) => (
          <button
            key={m}
            onClick={() => onMode(m)}
            className="border-2 border-black bg-white p-2 text-left"
            style={{
              outline: mode === m ? `2px solid ${dataset.theme.accent}` : undefined,
            }}
          >
            <p className="text-xs font-semibold text-[#5c5c5c]">{i.tag}</p>
            <div className="mt-2 flex justify-center">
              <Heatmap
                dataset={dataset}
                cells={c}
                mode={m}
                contrast={contrast}
                cellSize={12}
                showLabels={false}
                compact
              />
            </div>
          </button>
        ))}
      </div>
    </>
  );
}
